class MinHeap:
    def __init__(self):
        self.heap = []

    def _get_parent_index(self, index):
        return (index - 1) // 2

    def _get_left_child_index(self, index):
        return 2 * index + 1

    def _get_right_child_index(self, index):
        return 2 * index + 2

    def _has_parent(self, index):
        return self._get_parent_index(index) >= 0

    def _has_left_child(self, index):
        return self._get_left_child_index(index) < len(self.heap)

    def _has_right_child(self, index):
        return self._get_right_child_index(index) < len(self.heap)

    def _parent(self, index):
        return self.heap[self._get_parent_index(index)]

    def _left_child(self, index):
        return self.heap[self._get_left_child_index(index)]

    def _right_child(self, index):
        return self.heap[self._get_right_child_index(index)]

    def _swap(self, index1, index2):
        self.heap[index1], self.heap[index2] = self.heap[index2], self.heap[index1]

    def push(self, item):
        self.heap.append(item)
        self._heapify_up()

    def pop(self):
        if self.is_empty():
            raise IndexError("Heap is empty")
        if len(self.heap) == 1:
            return self.heap.pop()

        item = self.heap[0]
        self.heap[0] = self.heap.pop()
        self._heapify_down()
        return item

    def peek(self):
        if self.is_empty():
            raise IndexError("Heap is empty")
        return self.heap[0]

    def is_empty(self):
        return len(self.heap) == 0

    def __len__(self):
        return len(self.heap)

    def _heapify_up(self):
        current_index = len(self.heap) - 1
        while self._has_parent(current_index) and self._parent(current_index) > self.heap[current_index]:
            parent_index = self._get_parent_index(current_index)
            self._swap(current_index, parent_index)
            current_index = parent_index

    def _heapify_down(self):
        current_index = 0
        while self._has_left_child(current_index):
            smaller_child_index = self._get_left_child_index(current_index)
            if self._has_right_child(current_index) and self._right_child(current_index) < self._left_child(current_index):
                smaller_child_index = self._get_right_child_index(current_index)

            if self.heap[current_index] < self.heap[smaller_child_index]:
                break
            else:
                self._swap(current_index, smaller_child_index)
            current_index = smaller_child_index
